+type SMAPIItem struct {
+	ID       string `json:"id"`
+	ItemType string `json:"itemType"`
+	Title    string `json:"title"`
+	Summary  string `json:"summary,omitempty"`
+	MimeType string `json:"mimeType,omitempty"`
+}
